options.validator:
const fieldPrefix = arguments[0].field.split(".").slice(0, 2).join(".");
const maxUnitPrice = parseFloat(this.getValue(`${fieldPrefix}.purchase_max_price`));
const minUnitPrice = parseFloat(this.getValue(`${fieldPrefix}.purchase_min_price`));
const unitPrice = parseFloat(value);

if (maxUnitPrice > 0 && unitPrice > maxUnitPrice) {
  callback("Unit price cannot be greater than maximum unit price.");
} else if (minUnitPrice > 0 && unitPrice < minUnitPrice) {
  callback("Unit price cannot be less than minimum unit price.");
} else {
  callback();
}

