item.validator:
const page_status = this.getValue('page_status');

if (page_status === 'View' || !value) {
    callback();
    return;
}

let organizationId = this.getVarGlobal('deptParentId');
if(organizationId === '0'){
    organizationId = this.getVarSystem('deptIds').split(',')[0];
}

db.collection("supplier_head")
    .where({ supplier_code: value, organization_id: organizationId })
    .get()
    .then(response => {
        const matchingSuppliers = response.data || [];

        if (matchingSuppliers.length === 0) {
            callback();
            return;
        }

        if (page_status === 'Edit') {
            const currentSupplierID = this.getValue('id');
            const isSameSupplier = matchingSuppliers.some(supplier => supplier.id === currentSupplierID);
            callback(isSameSupplier ? undefined : 'Supplier code already exists.');
        } else {
            callback('Supplier code already exists.');
        }
    })
    .catch(error => {
        console.error("Error checking supplier:", error);
        callback("Error validating supplier code.");
    });

