(async () => {
  try {
    const variables = this.getValue("formula_variables");
    const operators = this.getValue("formula_operator");

    const filteredVariables = variables.filter(item => item.variable !== '')

    let variableArray = [];

    for (const v of filteredVariables) {
      if (/^[a-zA-Z]+$/.test(v.variable)) {
        variableArray.push(`{${v.variable}}`);
      } else if (/^-?\d*\.?\d+$/.test(v.variable)) {
        variableArray.push(v.variable);
      } else if (/^[a-zA-Z0-9]+$/.test(v.variable)) {
        throw new Error(
          "The string contains alphanumeric characters (letters and numbers)."
        );
      } else {
        throw new Error(
          "The string contains special characters or a mix of types."
        );
      }
    }

    let formulaPreview = "";

    if (filteredVariables.length <= operators.length) {
      operators.splice(filteredVariables.length);
    } else if (filteredVariables.length > operators.length) {
      while (operators.length < filteredVariables.length - 1) {
        operators.push({ operator_option: "+" });
      }
    }

    for (const [index, item] of filteredVariables.entries()) {
      if (formulaPreview === "") {
        formulaPreview = variableArray[index];
      } else {
        formulaPreview += operators[index - 1].operator_option;
        formulaPreview += variableArray[index];
      }
    }

    this.setData({
      formula_variables: filteredVariables,
      formula_operator: operators,
      formula_preview: formulaPreview,
    });
  } catch (error) {
    this.$message.error(error.toString());
  }
})();

