const validateFormulaStructure = async (formula) => {
  // Check if formula starts or ends with an operator
  const operatorPattern = /(\+|-|\*|\/|\^2|\^3)/;

  if (operatorPattern.test(formula[0])) {
    return {
      isValid: false,
      message: "Formula cannot start with an operator",
    };
  }

  if (operatorPattern.test(formula[formula.length - 1])) {
    return {
      isValid: false,
      message: "Formula cannot end with an operator",
    };
  }

  // Check for balanced parentheses
  let parenStack = [];
  for (let i = 0; i < formula.length; i++) {
    if (formula[i] === "(") {
      parenStack.push("(");
    } else if (formula[i] === ")") {
      if (parenStack.length === 0) {
        return {
          isValid: false,
          message:
            "Unbalanced parentheses: closing parenthesis without opening one",
        };
      }
      parenStack.pop();
    }
  }

  if (parenStack.length > 0) {
    return {
      isValid: false,
      message: "Unbalanced parentheses: missing closing parenthesis",
    };
  }

  // Remove parentheses for further validation (they're allowed for grouping)
  const withoutParens = formula.replace(/\(|\)/g, "");

  // Check if all variables/constants are enclosed in braces
  const bracePattern = /{([^}]+)}/g;
  let match;
  const braceMatches = [];

  while ((match = bracePattern.exec(formula)) !== null) {
    braceMatches.push(match[0]);
  }

  // Count the number of elements that should be in braces
  const elements = withoutParens
    .split(operatorPattern)
    .filter((item) => item.trim() !== "");

  console.log("elements", elements);

  const nonOperatorElements = elements.filter(
    (item) => !operatorPattern.test(item)
  );

  // Check for balanced parentheses
  let braceStack = [];
  for (let i = 0; i < nonOperatorElements.length; i++) {
    const splitNonOperatorElements = nonOperatorElements[i].trim();
    for (let j = 0; j < splitNonOperatorElements.length; j++) {
      if (splitNonOperatorElements[j] === "{") {
        braceStack.push("{");
      } else if (splitNonOperatorElements[j] === "}") {
        if (braceStack.length === 0) {
          return {
            isValid: false,
            message: "Unbalanced braces: closing brace without opening one",
          };
        }
        braceStack.pop();
      }
    }
  }

  if (braceStack.length > 0) {
    return {
      isValid: false,
      message: "Unbalanced braces: missing closing brace",
    };
  }

  const nonBraceElements = nonOperatorElements.filter(
    (item) => !item.startsWith("{") || !item.endsWith("}")
  );

  if (nonBraceElements.length > 0) {
    return {
      isValid: false,
      message: `Variables and constants must be enclosed in braces: ${nonBraceElements[0]}`,
    };
  }

  // Check if elements are properly connected with operators
  // Create a simplified version for operator validation
  const simplified = formula.replace(/{[^}]+}/g, "VAR").replace(/\(|\)/g, "");

  // Check for consecutive VARs (missing operators)
  if (/(VAR\s*){2,}/.test(simplified)) {
    return {
      isValid: false,
      message: "Variables must be connected with operators",
    };
  }

  // Check for consecutive operators
  const operatorRegex = /(\+|-|\*|\/|\^2|\^3)/;
  const singleCharOperatorPattern = /(\+|-|\*|\/)/;
  const powerOperatorPattern = /(\^2|\^3)/;
  const parts = simplified
    .split(operatorRegex)
    .filter((item) => item.trim() !== "");

  console.log("parts", parts);

  for (let i = 0; i < parts.length; i++) {
    if (parts[i] !== "VAR") {
      if (powerOperatorPattern.test(parts[i])) {
        if (i !== parts.length - 1) {
          if (parts[i + 1] === "VAR") {
            return {
              isValid: false,
              message: "Power operator must followed by operator",
            };
          }
        }
      } else if (singleCharOperatorPattern.test(parts[i])) {
        if (parts[i + 1] !== "VAR") {
          return {
            isValid: false,
            message: "Operator must followed by variable / constant",
          };
        }

        if (parts[i - 1] !== "VAR") {
          if (!powerOperatorPattern.test(parts[i - 1]))
            return {
              isValid: false,
              message: "Variables must be connected with operators",
            };
        }
      }
    }
  }

  return {
    isValid: true,
    message: "Formula is valid!",
  };
};

