console.log("Table:", tableReorderSupplier);
if (tableReorderSupplier.length > 0) {
  const validSupplier = tableReorderSupplier.filter(
    (supplier) => supplier.active === 1,
  );

  // Find the biggest value of the supplier_level in validSupplier and add 1 to it. If validSupplier is empty, start with 1.
  const newSupplierLevel =
    validSupplier.length > 1
      ? Math.max(...validSupplier.map((supplier) => supplier.supplier_level)) +
        1
      : 1;

  this.setData({
    [`table_reorder_supplier.${arguments[0].rowIndex}.supplier_level`]:
      newSupplierLevel,
  });
}

const tableReorderSupplier = this.getValue("table_reorder_supplier");
if (tableReorderSupplier.length > 0) {
  const validSupplier = tableReorderSupplier.filter(
    (supplier) => supplier.active === 1,
  );

  // Get all used supplier levels (including current row)
  const usedLevels = validSupplier
    .map((supplier) => supplier.supplier_level)
    .filter((level) => level !== null && level !== undefined && !isNaN(level));

  const currentLevel = arguments[0].value;
  const currentRowIndex = arguments[0].rowIndex;

  // Check for duplicates (excluding current row)
  const isDuplicate = validSupplier.some(
    (supplier, index) =>
      index !== currentRowIndex && supplier.supplier_level === currentLevel,
  );

  // Check if the current level larger than the largest used level
  const usedLevelsExceptCurrent = validSupplier
    .filter((supplier, index) => index !== currentRowIndex)
    .map((supplier) => supplier.supplier_level);
  const isLargerThanMax =
    currentLevel > Math.max(...usedLevelsExceptCurrent) &&
    currentLevel > usedLevelsExceptCurrent.length;

  console.log(
    `isDuplicate: ${isDuplicate}, isLargerThanMax: ${isLargerThanMax}`,
  );

  if (isDuplicate || isLargerThanMax) {
    // Find smallest available level
    let newLevel = 1;
    const sortedLevels = [...usedLevels].sort((a, b) => a - b);

    // Find the smallest positive integer not in usedLevels
    for (let i = 0; i < sortedLevels.length; i++) {
      if (sortedLevels[i] === newLevel) {
        newLevel++;
      } else if (sortedLevels[i] > newLevel) {
        break;
      }
    }

    // Show alert
    this.$alert(
      `Supplier level ${currentLevel} invalid.\n\n` +
        `It has been automatically changed to ${newLevel}.`,
    );

    // Update the value
    this.setData({
      [`table_reorder_supplier.${currentRowIndex}.supplier_level`]: newLevel,
    });
  }
}

